messages.content:
RISKS:
[
 {
  "riskId": "risk.execution-window.firmware-security-audit-gate",
  "title": "The firmware/security audit gate precedes every intelligent-PDU listing — and it isn't in the funnel",
  "claim": "An intelligent PDU is a networked device sitting on the management LAN of critical infrastructure. Before any large CE operator issues a PO, the vendor must clear a security prequalification that a dumb-metal vendor never faces: vulnerability disclosure process, signed-firmware update infrastructure, SBOM, penetration evidence, increasingly IEC 62443-style artifacts as the EU Cyber Resilience Act obligations phase in. This gate is serial with — not parallel to — CE/TÜV product certification, and it is audited against infrastructure the pre-launch venture has to build during the very year YAM assumes it is harvesting. The serviceableFactor's 0.55 haircut names only the classic cert stack; the security gate is a second, slower door in front of the same customers, and it opens per-operator, not per-product.",
  "falsifier": "Two or more large CE operators (or their integrators) issuing rack-PDU RFQs in the venture's first two quarters with no firmware-security/SBOM prequalification requirement, or confirming that product CE marking alone suffices for AVL listing."
 },
 {
  "riskId": "risk.execution-window.framework-agreements-foreclose-large-operator-cell",
  "title": "Global framework agreements make the 0.40 large-operator cell mostly non-contestable in the venture's window",
  "claim": "The model's biggest customer cell — large operators at 0.40 of PDU spend — encodes the assumption 'large operators buy direct, therefore a direct-selling entrant can compete for them.' But the way large operators buy direct is through multi-year global framework agreements and integrated infrastructure packages with incumbents whose customer lists already span every hyperscaler and major colo. A framework doesn't shrink the cell's spend; it forecloses it: the PDU line is decided once, globally, years at a time, and never comes to regional tender. For a pre-launch regional entrant whose profile explicitly targets large operators first, the nominal 0.40 collapses to the sliver of that spend outside framework coverage — while the model's YAM math quietly credits the whole cell as contestable.",
  "falsifier": "Three CE large-operator procurement interviews (or won/lost tender records) showing rack-PDU purchases regularly competed line-by-line at regional level outside global frameworks — e.g., annual PDU bake-offs open to non-incumbent vendors."
 },
 {
  "riskId": "risk.execution-window.prelet-pipeline-lockout",
  "title": "The growth the CAGR promises was electrically specified before launch day — Year 1 can only sell into the installed base",
  "claim": "Nine percent CAGR reads as a tailwind: new halls, new racks, new PDU line items every quarter of Year 1. But new-build DC electrical procurement is locked at design freeze, and with long-lead power equipment (transformers, switchgear) now booked years out, operators are locking entire electrical BOMs — PDUs riding along — far earlier than the 12–24-month window the ledger's own crossCheck uses to justify its ceiling. Every megawatt that energizes during the venture's first 12 months had its rack-power vendor chosen while the venture was still pre-launch. That leaves Year-1 demand confined to retrofit, refresh and expansion churn in the installed base — a materially smaller and slower pool than 'the market' — while the model applies its 1% to the whole SAM as if new-build spend were reachable on the venture's clock.",
  "falsifier": "Documented cases of CE new-build data centers running competitive rack-PDU selection within 6 months of fit-out (i.e., inside the venture's selling window), or an operator confirming PDUs are procured late as a commodity line decoupled from the electrical design freeze."
 },
 {
  "riskId": "risk.execution-window.mid-eichrecht-metering-foreclosure",
  "title": "MID/Eichrecht-grade metering gates the billing use case in Germany — half the geography, the core intelligent-PDU value prop",
  "claim": "The intelligent PDU's premium over dumb power strips rests substantially on outlet- and rack-level metering. But in Germany — 50% of the modeled geography — any meter whose readings are used to bill sub-tenants per measured kWh falls under legal-metrology obligations (MessEG/MID): the metering chain must be conformity-assessed, not merely accurate. A pre-launch entrant whose PDU metering is 'billing-grade' in spec but not MID-certified in law cannot sell the billing use case to German colos at all, and MID module certification is its own multi-quarter, notified-body process that is nowhere on the launch-critical path. The serviceableFactor's 0.55 bundles 'EU cert stack' into one qualitative haircut and never distinguishes this instrument — yet it forecloses the highest-value slice of demand in the largest country cell.",
  "falsifier": "Confirmation from two German colocation operators (or the responsible eichamt/PTB guidance) that PDU-level metering used for tenant re-billing is exempt from MessEG conformity requirements in their billing model, or that estimate/capacity-tier billing makes MID-certified PDU metering commercially irrelevant to their purchase decision."
 }
]

Emit JSON: { items: [{riskId, queries: [{query, kind: confirming|falsifying|base-rate}]}] } — 3 queries per risk.
